import json

# Check available variables
all_vars = list(locals().keys())
vardict = {}
for k in all_vars:
    if k.startswith('var_'):
        v = locals()[k]
        v_type = type(v).__name__
        if isinstance(v, list):
            v_preview = str(v[:3])
        else:
            v_preview = str(v)[:100]
        vardict[k] = {'type': v_type, 'preview': v_preview}

print('__RESULT__:')
print(json.dumps(vardict, indent=2))

